mapper.select:
SELECT b.POST_SN, b.POST_SJ, b.POST_CN, b.WRTR_USER_ID, b.ATCH_FILE_ID, b.INQ_CNT, b.REG_DT, b.MDFCN_DT, d.DATA_CTG, d.EXPS_ORD, d.ACCS_LMT_CD, c1.COM_CD_NM AS DATA_CTG_NM, c2.COM_CD_NM AS ACCS_LMT_NM FROM BOARD b JOIN DATA_ROOM d ON b.POST_SN = d.POST_SN LEFT JOIN COM_CD c1 ON c1.COM_CD = d.DATA_CTG AND c1.CL_CODE = '106' LEFT JOIN COM_CD c2 ON c2.COM_CD = d.ACCS_LMT_CD AND c2.CL_CODE = '107' WHERE b.BOARD_TYPE_CD = '04'
AND d.DATA_CTG = #{dataCtg}
ORDER BY b.REG_DT DESC

mapper.update:
UPDATE DATA_ROOM SET
    DATA_CTG    = #{dataCtg},
    ACCS_LMT_CD = #{accsLmtCd}
WHERE POST_SN = #{postSn}
